query:
-- 1. Deletar todos os lançamentos de Prolabore (não existem no Excel)
DELETE FROM transactions 
WHERE description LIKE 'Prolabore%' AND source = 'import_excel';

-- 2. Corrigir os valores do Salário da Aline (valores reais do Excel)
UPDATE transactions SET amount = 2447.29 
WHERE description = 'Salario (Aline)' AND source = 'import_excel' AND dueDate = '2026-01-01';

UPDATE transactions SET amount = 1201.57 
WHERE description = 'Salario (Aline)' AND source = 'import_excel' AND dueDate = '2026-02-01';

UPDATE transactions SET amount = 2718.81 
WHERE description = 'Salario (Aline)' AND source = 'import_excel' AND dueDate = '2026-03-01';

UPDATE transactions SET amount = 2718.81 
WHERE description = 'Salario (Aline)' AND source = 'import_excel' AND dueDate = '2026-04-01';

UPDATE transactions SET amount = 2718.81 
WHERE description = 'Salario (Aline)' AND source = 'import_excel' AND dueDate = '2026-05-01';

-- 3. Verificar o resultado
SELECT description, amount, dueDate, status 
FROM transactions 
WHERE description LIKE 'Salario%' AND source = 'import_excel'
ORDER BY dueDate;

